const tema = ($json.body && $json.body.tema) || $json.tema;
if (!tema || typeof tema !== 'string') throw new Error('campo "tema" obrigatório no body');
const slug = tema.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 60);
const runDir = `/data/outputs/${slug}-${Date.now()}`;
const fs = require('fs');
fs.mkdirSync(`${runDir}/assets`, { recursive: true });
return [{ json: { tema, slug, runDir } }];

const ctx = $('Parse Input').item.json;
const folderId = $('Drive Create Folder').item.json.id;
const metaPrompt = $json.stdout;
if (!metaPrompt || metaPrompt.length < 100) throw new Error('meta_prompt_copy.md não encontrado em /data/scripts/');
return [{ json: { ...ctx, metaPrompt, driveFolderId: folderId } }];

const raw = $json.candidates && $json.candidates[0] && $json.candidates[0].content.parts[0].text;
if (!raw) throw new Error('Gemini não retornou texto. Resposta: ' + JSON.stringify($json).slice(0, 500));
let copy;
try { copy = JSON.parse(raw); } catch (e) { throw new Error('JSON inválido do Gemini: ' + raw.slice(0, 400)); }
if (!copy.slides || copy.slides.length < 5 || copy.slides.length > 15)
  throw new Error('n_slides fora do range 5-15 (recebido: ' + (copy.slides||[]).length + ')');
if (copy.slides[0].tipo !== 'hook') throw new Error('slide 1 precisa ser tipo "hook"');
if (copy.slides[copy.slides.length-1].tipo !== 'cta') throw new Error('último slide precisa ser tipo "cta"');
const ctx = $('Parse Input').item.json;
const folderId = $('Drive Create Folder').item.json.id;
const fs = require('fs');
fs.writeFileSync(`${ctx.runDir}/copy.json`, JSON.stringify(copy, null, 2));
fs.writeFileSync(`${ctx.runDir}/caption.md`, copy.caption || '');
return copy.slides.map(s => ({ json: {
  ...s,
  runDir: ctx.runDir,
  slug: ctx.slug,
  tema: ctx.tema,
  driveFolderId: folderId,
  totalSlides: copy.slides.length,
  caption: copy.caption,
  copyRaw: copy
}}));

