const fs = require('fs');
const slide = $('Loop Slides').item.json;
const parts = ($json.candidates && $json.candidates[0] && $json.candidates[0].content.parts) || [];
const imgPart = parts.find(p => p.inline_data || p.inlineData);
if (!imgPart) throw new Error('Gemini Image não retornou imagem para slide ' + slide.n);
const data = (imgPart.inline_data || imgPart.inlineData).data;
const n = String(slide.n).padStart(2, '0');
const assetPath = `${slide.runDir}/assets/slide_${n}.png`;
const slidePath = `${slide.runDir}/slide_${n}.png`;
const slideJsonPath = `${slide.runDir}/assets/slide_${n}.json`;
fs.writeFileSync(assetPath, Buffer.from(data, 'base64'));
fs.writeFileSync(slideJsonPath, JSON.stringify(slide));
return [{ json: { ...slide, assetPath, slidePath, slideJsonPath, n } }];

if ($json.exitCode && $json.exitCode !== 0) throw new Error('compose_slide.py falhou: ' + ($json.stderr || ''));
const slide = $('Save Asset').item.json;
const fs = require('fs');
const buf = fs.readFileSync(slide.slidePath);
return [{
  json: { ...slide },
  binary: { data: { data: buf.toString('base64'), mimeType: 'image/png', fileName: `slide_${slide.n}.png` } }
}];

const uploads = $('Drive Upload Slide').all();
const ctx = $('Parse Input').item.json;
const copy = $('Validate & Split Slides').first().json.copyRaw;
const folderId = $('Drive Create Folder').item.json.id;
const slides = uploads.map(u => ({
  n: u.json.n,
  name: u.json.name,
  url: u.json.webViewLink || u.json.webContentLink || null,
  id: u.json.id
})).sort((a, b) => String(a.n).localeCompare(String(b.n)));
return [{ json: {
  ok: true,
  slug: ctx.slug,
  tema: ctx.tema,
  n_slides: slides.length,
  folderId,
  folderUrl: `https://drive.google.com/drive/folders/${folderId}`,
  slides,
  caption: copy.caption,
  padroes_usados: copy.padroes_usados || []
}}];
